parameters.jsCode:
const output = $json.output || {};
const retrieval = $json.retrieval || {};
const body = $json.body || {};
const stringArray = (value) => Array.isArray(value)
  ? value.map((item) => String(item || '').trim()).filter(Boolean)
  : [];
const previousMessages = Array.isArray(body.previous_messages) ? body.previous_messages : [];
const formattedHistory = previousMessages
  .map((message) => `${String(message.role || '').trim()}: ${String(message.content || '').trim()}`)
  .filter((line) => line.length > 2)
  .join('\n');
const rag = {
  original_message: String(output.original_message || '').trim(),
  legal_category: String(output.category || '').trim(),
  canonical_category: String(retrieval.canonicalCategory || '').trim(),
  canonical_subcategories: stringArray(retrieval.canonicalSubcategories),
  metadata_hints: stringArray(retrieval.metadataHints),
  search_terms: stringArray(retrieval.searchTerms),
  file_search_store_name: String($json['Search Store'] || '').trim(),
  previous_messages: previousMessages
};
const rag_prompt = [
  `Mensaje del usuario: "${rag.original_message}"`,
  `Historial persistido reciente:\n${formattedHistory || '(sin mensajes previos)'}`,
  `Categoria: "${rag.legal_category}"`,
  `Categoria canonica: "${rag.canonical_category}"`,
  `Subcategorias canonicas: "${rag.canonical_subcategories.join(', ')}"`,
  `Metadata preferida: "${rag.metadata_hints.join(' ')}"`,
  `Terminos de busqueda: "${rag.search_terms.join(', ')}"`
].join('\n');
return [{ json: { ...$json, rag, rag_prompt } }];

