{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "ExplainableAnswer",
  "type": "object",
  "properties": {
    "answer": {
      "type": "string",
      "description": "Final user-facing Spanish Markdown answer with personalized orientation, preliminary legal alternatives, useful next steps, glossary when helpful, and prudent caveats."
    },
    "citations": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "file_id": {
            "type": "string"
          },
          "file_name": {
            "type": "string"
          },
          "snippet": {
            "type": "string",
            "description": "One short Spanish safe summary of the relevant evidence from this file. Summarize across all retrieved snippets for the same file, mention only why it matters, and do not copy exact text or expose sensitive personal details from jurisprudence."
          },
          "file_url": {
            "type": "string"
          }
        },
        "additionalProperties": true
      }
    },
    "citationSupportStatus": {
      "type": "string",
      "enum": [
        "GOOD",
        "WEAK",
        "NONE"
      ]
    },
    "confidenceStatus": {
      "type": "string",
      "enum": [
        "HIGH",
        "MEDIUM",
        "LOW"
      ]
    },
    "confidenceReason": {
      "type": "string"
    },
    "specialistSupportRecommended": {
      "type": "boolean"
    },
    "nextSteps": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Concrete next steps only for in-scope legal guidance. Return [] for greetings, out-of-scope messages, or when no useful next step follows from the answer."
    }
  },
  "required": [
    "answer",
    "citations",
    "citationSupportStatus",
    "confidenceStatus",
    "nextSteps",
    "specialistSupportRecommended"
  ],
  "additionalProperties": false
}
